starterCss:
/* Refactor these repetitive selectors using :is(), :where(), and :not():
   1. All headings should be dark blue
   2. All paragraphs except .intro should be gray
   3. List items that are not .disabled should be bold */
.content h1 {
  color: #1a365d;
}
.content h2 {
  color: #1a365d;
}
.content h3 {
  color: #1a365d;
}
.content p {
  color: #6c757d;
  line-height: 1.6;
}
.content p.intro {
  color: #333;
  font-size: 18px;
  /* BUG: this should override the gray, but p.intro is same specificity as the gray rule */
}
.feature-list li {
  font-weight: bold;
  padding: 4px 0;
}
.feature-list li.disabled {
  font-weight: normal;
  opacity: 0.5;
  /* BUG: need to undo bold, but specificity fight */
}

referenceSolutions:
.content :is(h1, h2, h3) {
  color: rgb(26, 54, 93);
}
.content p:not(.intro) {
  color: rgb(108, 117, 125);
}
.content p {
  line-height: 1.6;
}
.content .intro {
  color: rgb(51, 51, 51);
  font-size: 18px;
}
.feature-list li:not(.disabled) {
  font-weight: 700;
  padding: 4px 0;
}
.feature-list li.disabled {
  font-weight: 400;
  opacity: 0.5;
  padding: 4px 0;
}

.content :is(h1, h2, h3) {
  color: #1a365d;
}
.content :where(p) {
  line-height: 1.6;
}
.content p:not(.intro) {
  color: #6c757d;
}
.content p.intro {
  color: #333;
  font-size: 18px;
}
.feature-list li:not(.disabled) {
  font-weight: bold;
  padding: 4px 0;
}
.feature-list .disabled {
  font-weight: normal;
  opacity: 0.5;
  padding: 4px 0;
}

